package Collections_java;

public class CompareTo_java {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		String s1 = "apple";
		String s2 = "banana";
		System.out.println(s1.compareTo(s2)); // negative
		System.out.println(s2.compareTo(s1)); // positive
		System.out.println(s1.compareTo("apple"));	//zero
		
		
		/*
		 * compareTo compares lexicographically:
		 *  Negative: s1 < s2 - 
		 *  Positive: s1 > s2
		 * Zero: s1 equals s2
		 */
		
		
		
		
		
	}

}
